const registrosRaw = $json.view_ind_formulario || [];

// 2. FILTRADO INMUTABLE: Extraemos únicamente el Riesgo País usando su ID único ("val_ind_0003")
const datosRiesgo = registrosRaw.filter(item => 
  item["CÃ³digo Variable DinÃ¡mica"] === "val_ind_0003" || 
