);

// 3. CONTROL DE ERRORES: Si el dataset no contiene el indicador, activa la contingencia activa
if (datosRiesgo.length === 0) {
  return [
    {
      json: {
        INDICADOR: "RIESGO_PAIS",
        FECHA_FISCAL: item.Fecha,
        FECHA_EXTRACCION: new Date(),
        ESTADO: "INCOMPLETO",
