      }
    }
  ];
}

// 4. TRADUCCIÓN Y MAPEO MASIVO: Formateamos toda la historia directo para la base relacional Oracle
return datosRiesgo.map(item => {
  // Limpieza de texto y conversión de String a Flotante (ej: "870" -> 870.0)
  const valorRaw = item.Valor ? item.Valor.toString().trim().replace(',', '.') : "";
  const valorNumerico = parseFloat(valorRaw);
  const esValido = !isNaN(valorNumerico);

  return {
    json: {
      INDICADOR: "RIESGO_PAIS",
      FECHA_FISCAL: item.Fecha,
      FECHA_EXTRACCION: new Date(), // Trazabilidad de la carga relacional
      ESTADO: esValido ? "COMPLETO" : "INCOMPLETO",
      NECESITA_RESPALDO: esValido ? 0 : 1,
      DETALLE_ERROR: esValido ? "" : "Valor histórico de Riesgo País con formato no numérico.",
      // Empaquetamos el documento JSON sanitizado libre de Mojibake
      DATOS_JSON: JSON.stringify({
        fecha_fiscal: item.Fecha, // Almacena la fecha macroeconómica real (ej: 2004-07-29)
        valor: esValido ? valorNumerico : null,
        indicador_limpio: "Riesgo País", // Reconstrucción limpia de caracteres
        medida: "Puntos Básicos",
        fuente: "Banco Central del Ecuador",
        ruta_logica: "BCE/PUBLICACIONES_GENERALES/RIESGO_PAIS" // Equivalencia del esquema de carpetas
      })
    }
  };
});
